import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"绝地长袍","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/绝地长袍.md","filePath":"4.资源分区/7.物品与装备/3.防具/7.可升级/绝地长袍.md"}'),d={name:"4.资源分区/7.物品与装备/3.防具/7.可升级/绝地长袍.md"};function b(l,e,p,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"绝地长袍",tabindex:"-1"},[s("绝地长袍 "),r("a",{class:"header-anchor",href:"#绝地长袍","aria-label":'Permalink to "绝地长袍"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"汹涌疾风022")])])],-1),o('<h1 id="绝地长袍-1" tabindex="-1">绝地长袍 <a class="header-anchor" href="#绝地长袍-1" aria-label="Permalink to &quot;绝地长袍&quot;">​</a></h1><p>绝地长袍<br> 绝地武士的长袍通常由外袍和前襟两部分组成。外袍长度从及膝至脚踝可自由定制；前襟则具有两条对称布条挂在身前。此番设计考虑了绝地武士们的穿着舒适性、肢体活动自由度以及对原力的亲和性，兼顾了实用性与功能性。</p><p>绝地学徒长袍<br> D+500<br> 类型：轻甲<br> 偏斜防御：0/0<br> 特性：【防弹】<br> 绝地长袍的材质能确保穿着者免受一定程度的恶劣天气条件，令穿戴者免疫D级别、环境来源的负面效果。<br> 【原力导延】：若穿着者的原力池不空，则该护甲的偏斜防御提升至5/5。角色可以花招动作消耗1点原力在场景内将该护甲的偏斜防御提升至8/8。<br> 【多功能腰囊】：角色获得四个仅能放置体积不超过1物品的消耗品栏位。</p><p>绝地武士长袍<br> C+1500<br> 可由绝地学徒长袍差价升级。<br> 类型：轻甲<br> 偏斜防御：0/0<br> 特性：【防弹】<br> 绝地长袍的材质能确保穿着者免受一定程度的恶劣天气条件，令穿戴者免疫C级别、环境来源的负面效果。<br> 【原力导延】：若穿着者的原力池不空，则该护甲的偏斜防御提升至10/10。角色可以迅捷动作消耗3点原力在场景内将该护甲的偏斜防御提升至16/16，并获得基于此护甲防御类型的【适应】。<br> 【多功能腰囊】：角色获得四个仅能放置体积不超过1物品的消耗品栏位。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(d,[["render",b]]);export{f as __pageData,m as default};
